  1→use std::sync::Mutex;
  2→use tauri::{Emitter, Manager};
  3→#[cfg(desktop)]
  4→use tauri::menu::{Menu, MenuItem, PredefinedMenuItem};
  5→#[cfg(desktop)]
  6→use tauri::tray::{MouseButton, MouseButtonState, TrayIconBuilder, TrayIconEvent};
  7→#[cfg(desktop)]
  8→use tauri_plugin_global_shortcut::{Code, GlobalShortcutExt, Modifiers, Shortcut, ShortcutState};
  9→
 10→struct WindowConfig {
 11→    position_pref: String,
 12→}
 13→
 14→impl Default for WindowConfig {
 15→    fn default() -> Self {
 16→        Self {
 17→            position_pref: "top-third".to_string(),
 18→        }
 19→    }
 20→}
 21→
 22→fn position_near_top(window: &tauri::WebviewWindow) {
 23→    let monitor = window
 24→        .current_monitor()
 25→        .ok()
 26→        .flatten()
 27→        .or_else(|| window.primary_monitor().ok().flatten());
 28→
 29→    if let Some(monitor) = monitor {
 30→        let monitor_size = monitor.size();
 31→        let monitor_pos = monitor.position();
 32→
 33→        if let Ok(window_size) = window.outer_size() {
 34→            let x = monitor_pos.x + (monitor_size.width as i32 - window_size.width as i32) / 2;
 35→            let y = monitor_pos.y + (monitor_size.height as i32) / 5;
 36→
 37→            if let Err(e) = window.set_position(tauri::PhysicalPosition::new(x, y)) {
 38→                eprintln!("failed to position window: {e}");
 39→            }
 40→        }
 41→    } else if let Err(e) = window.center() {
 42→        eprintln!("failed to center window: {e}");
 43→    }
 44→}
 45→
 46→fn show_and_focus(window: &tauri::WebviewWindow) {
 47→    let position_pref = window
 48→        .app_handle()
 49→        .try_state::<Mutex<WindowConfig>>()
 50→        .and_then(|state| state.lock().ok().map(|s| s.position_pref.clone()))
 51→        .unwrap_or_else(|| "top-third".to_string());
 52→
 53→    if position_pref == "center" {
 54→        if let Err(e) = window.center() {
 55→            eprintln!("failed to center window: {e}");
 56→        }
 57→    } else {
 58→        position_near_top(window);
 59→    }
 60→
 61→    if let Err(e) = window.show() {
 62→        eprintln!("failed to show window: {e}");
 63→    }
 64→    if let Err(e) = window.set_focus() {
 65→        eprintln!("failed to focus window: {e}");
 66→    }
 67→}
 68→
 69→fn toggle_window(window: &tauri::WebviewWindow) {
 70→    let visible = window.is_visible().unwrap_or(false);
 71→    let focused = window.is_focused().unwrap_or(false);
 72→
 73→    if visible && focused {
 74→        if let Err(e) = window.hide() {
 75→            eprintln!("failed to hide window: {e}");
 76→        }
 77→    } else if visible {
 78→        show_and_focus(window);
 79→    } else {
 80→        show_and_focus(window);
 81→    }
 82→}
 83→
 84→#[tauri::command]
 85→fn set_window_position_pref(
 86→    state: tauri::State<'_, Mutex<WindowConfig>>,
 87→    position: String,
 88→) -> Result<(), String> {
 89→    match position.as_str() {
 90→        "center" | "top-third" => {
 91→            if let Ok(mut config) = state.lock() {
 92→                config.position_pref = position;
 93→                Ok(())
 94→            } else {
 95→                Err("failed to acquire config lock".to_string())
 96→            }
 97→        }
 98→        _ => Err(format!("invalid position: {position}")),
 99→    }
100→}
101→
102→#[cfg_attr(mobile, tauri::mobile_entry_point)]
103→pub fn run() {
104→    tauri::Builder::default()
105→        .manage(Mutex::new(WindowConfig::default()))
106→        .invoke_handler(tauri::generate_handler![set_window_position_pref])
107→        .setup(|app| {
108→            #[cfg(desktop)]
109→            {
110→                let shortcut = Shortcut::new(Some(Modifiers::ALT), Code::Space);
111→                let window = app
112→                    .get_webview_window("main")
113→                    .expect("main window not found");
114→
115→                let window_for_blur = window.clone();
116→                window.on_window_event(move |event| {
117→                    if let tauri::WindowEvent::Focused(false) = event {
118→                        if let Err(e) = window_for_blur.hide() {
119→                            eprintln!("failed to hide on blur: {e}");
120→                        }
121→                    }
122→                });
123→
124→                #[cfg(target_os = "macos")]
125→                {
126→                    use window_vibrancy::{apply_vibrancy, NSVisualEffectMaterial};
127→                    if let Err(e) =
128→                        apply_vibrancy(&window, NSVisualEffectMaterial::HudWindow, None, None)
129→                    {
130→                        eprintln!("failed to apply vibrancy: {e}");
131→                    }
132→                }
133→
134→                position_near_top(&window);
135→
136→                let window_for_shortcut = window.clone();
137→                app.handle().plugin(
138→                    tauri_plugin_global_shortcut::Builder::new()
139→                        .with_handler(move |_app, scut, event| {
140→                            if scut == &shortcut && event.state() == ShortcutState::Pressed {
141→                                toggle_window(&window_for_shortcut);
142→                            }
143→                        })
144→                        .build(),
145→                )?;
146→
147→                app.global_shortcut().register(shortcut)?;
148→
149→                let show_item =
150→                    MenuItem::with_id(app, "show", "Show Raycast", true, None::<&str>)?;
151→                let clipboard_item =
152→                    MenuItem::with_id(app, "clipboard", "Clipboard History", true, None::<&str>)?;
153→                let snippets_item =
154→                    MenuItem::with_id(app, "snippets", "Snippets", true, None::<&str>)?;
155→                let settings_item =
156→                    MenuItem::with_id(app, "settings", "Settings", true, None::<&str>)?;
157→                let check_updates_item = MenuItem::with_id(
158→                    app,
159→                    "check-updates",
160→                    "Check for Updates",
161→                    true,
162→                    None::<&str>,
163→                )?;
164→                let about_item =
165→                    MenuItem::with_id(app, "about", "About Raycast Clone", true, None::<&str>)?;
166→                let quit_item = MenuItem::with_id(app, "quit", "Quit", true, None::<&str>)?;
167→
168→                let menu = Menu::with_items(
169→                    app,
170→                    &[
171→                        &show_item,
172→                        &PredefinedMenuItem::separator(app)?,
173→                        &clipboard_item,
174→                        &snippets_item,
175→                        &settings_item,
176→                        &PredefinedMenuItem::separator(app)?,
177→                        &check_updates_item,
178→                        &about_item,
179→                        &quit_item,
180→                    ],
181→                )?;
182→
183→                let window_for_menu = window.clone();
184→                let window_for_tray = window.clone();
185→
