                app.global_shortcut().register(shortcut)?;

                let show_item =
                    MenuItem::with_id(app, "show", "Show Raycast", true, None::<&str>)?;
                let clipboard_item =
                    MenuItem::with_id(app, "clipboard", "Clipboard History", true, None::<&str>)?;
