}

const FILTER_SECTIONS: SearchDropdownSection[] = [
  {
    options: [
      {
        label: 'All',
        value: 'all',
      },
    ],
  },
  {
    title: 'Type',
    options: [
      {
        label: 'Text',
        value: 'text',
      },
      {
        label: 'Links',
        value: 'link',
